import React, { useContext } from "react";
import { GlobalContext } from "../context/GlobalState";

const MovieControls = ({ movie, type }) => {
  const {
    removeMovieFromWatchlist,
    addMovieToWatched,
    moveToWatchlist,
    removeMovieFromWatched,
  } = useContext(GlobalContext);
  return (
    <div className="inner-card-controls">
      {type === "watchlist" && (
        <>
          <button
            className="ctrl-btn"
            aria-label="İzlenenler listesine taşı"
            title="İzlenenler listesine taşı"
            onClick={() => addMovieToWatched(movie)}
            type="button"
          >
            <i className="fa-fw far fa-eye"></i>
          </button>
          <button
            className="ctrl-btn"
            aria-label="Watchlist'ten kaldır"
            title="Watchlist'ten kaldır"
            onClick={() => removeMovieFromWatchlist(movie.id)}
            type="button"
          >
            <i className="fa-fw fa fa-times"></i>
          </button>
        </>
      )}

      {type === "watched" && (
        <>
          <button
            className="ctrl-btn"
            aria-label="Watchlist'e geri taşı"
            title="Watchlist'e geri taşı"
            onClick={() => moveToWatchlist(movie)}
            type="button"
          >
            <i className="fa-fw far fa-eye-slash"></i>
          </button>
          <button
            className="ctrl-btn"
            aria-label="İzlenenler listesinden kaldır"
            title="İzlenenler listesinden kaldır"
            onClick={() => removeMovieFromWatched(movie.id)}
            type="button"
          >
            <i className="fa-fw fa fa-times"></i>
          </button>
        </>
      )}
    </div>
  );
};

export default MovieControls;
